L_val   = 0.01      # Henry
C_val   = 1e-5      # Farad
R_init  = 10.0      # Ohm  (slider will change this)
f_sq    = 100.0     # Hz  square-wave frequency
fs      = 50_000    # samples / second
t_end   = 0.05      # seconds to display

t = np.linspace(0, t_end, int(fs * t_end), endpoint=False)
u = signal.square(2 * np.pi * f_sq * t)   # ±1 square wave

def compute_output(R):
    """Simulate series RLC driven by square wave; return output voltage across C."""
    # Transfer function  H(s) = ω₀² / (s² + 2ζω₀ s + ω₀²)
    w0 = 1.0 / np.sqrt(L_val * C_val)
    num = [w0**2]
    den = [1.0, R / L_val, w0**2]
    sys = signal.TransferFunction(num, den)
    _, y, _ = signal.lsim(sys, u, t)
    return y

# ─────────────────────────────────────────────
# Figure layout
# ─────────────────────────────────────────────
fig = plt.figure(figsize=(14, 9))
