    ax.plot([x_left, 2.5],   [y_top, y_top], **wire_kw)   # left → R
    ax.plot([4.5, 6.0],      [y_top, y_top], **wire_kw)   # R → L
    ax.plot([8.0, x_right],  [y_top, y_top], **wire_kw)   # L → right node

    # Right vertical wire
    ax.plot([x_right, x_right], [y_top, y_bot], **wire_kw)

    # Bottom wire segments
    ax.plot([x_right, 7.0], [y_bot, y_bot], **wire_kw)    # right → C
    ax.plot([5.0, x_left],  [y_bot, y_bot], **wire_kw)    # C → left

    # ── Voltage source (left side) ─────────────────────────────────────
    cx, cy = x_left, (y_top + y_bot) / 2
    circle = plt.Circle((cx, cy), 0.55, color='#ff6b6b', fill=False, lw=lw)
    ax.add_patch(circle)
    ax.text(cx, cy + 0.18, '+', color='#ff6b6b', ha='center', va='center', fontsize=11, fontweight='bold')
    ax.text(cx, cy - 0.22, '−', color='#ff6b6b', ha='center', va='center', fontsize=13, fontweight='bold')
    ax.text(cx - 0.9, cy, 'Vin\n(sq)', color='#ff6b6b', ha='center', va='center', fontsize=8)

    # ── Resistor (top, left section) ──────────────────────────────────
    rx0, rx1 = 2.5, 4.5
    ry = y_top
    # Zigzag
    n_teeth = 6
    xs = np.linspace(rx0, rx1, n_teeth * 2 + 1)
    ys = np.array([ry + (0.3 if i % 2 == 1 else -0.3) if 0 < i < len(xs)-1 else ry
                   for i in range(len(xs))])
    ys[0] = ry; ys[-1] = ry
    ax.plot(xs, ys, **comp_kw)
    ax.text((rx0+rx1)/2, ry + 0.75, f'R = {R:.1f} Ω', color='#ffdd44',
            ha='center', va='bottom', fontsize=10, fontweight='bold')

    # ── Inductor (top, right section) ─────────────────────────────────
    lx0, lx1 = 6.0, 8.0
