    # ── Output label ──────────────────────────────────────────────────
    ax.annotate('', xy=(x_right, y_bot + 0.3), xytext=(x_right, y_top - 0.3),
                arrowprops=dict(arrowstyle='<->', color='#ff9944', lw=1.5))
    ax.text(x_right + 0.35, (y_top + y_bot)/2, 'Vout', color='#ff9944',
            ha='left', va='center', fontsize=9, rotation=90)

